        },
        {
          "name": "phone_number",
          "label": "Phone Number",
          "required": false,
          "type": "PHONE"
        },
        {
          "name": "additional_comments",
          "label": "Additional Comments",
          "required": false,
          "type": "TEXT",
          "multiline": true,
          "validations": {
            "maxLength": 500
          }
        }
      ]
    }
  ]
}

