{
  "name": "New Customer Application",
  "language": "EN",
  "description": "Demonstrates conditional fields and sections. The Business Details section only appears for business customers. The Agreement ID field only appears when the user indicates an existing agreement.",
  "sections": [
    {
      "title": "Personal Information",
      "fields": [
        {
          "name": "full_name",
          "label": "Full Name",
          "required": true,
          "type": "TEXT",
          "validations": {
            "minLength": 2,
            "maxLength": 100
          }
        },
        {
          "name": "email_address",
          "label": "Email Address",
          "required": true,
          "type": "EMAIL"
        },
        {
          "name": "customer_type",
          "label": "Customer Type",
          "required": true,
          "type": "CHOICE",
          "layout": "RADIO",
          "options": [
            {
              "label": "Individual",
              "value": "individual"
            },
            {
              "label": "Business",
              "value": "business"
            }
          ]
        }
      ]
    },
    {
      "title": "Business Details",
      "condition": {
        "rules": [
          {
            "field": "customer_type",
            "operator": "EQUALS",
            "value": "business"
          }
        ]
      },
      "fields": [
        {
          "name": "company_name",
          "label": "Company Name",
          "required": true,
          "type": "TEXT",
          "validations": {
            "maxLength": 200
          }
        },
        {
          "name": "company_registration",
          "label": "Company Registration Number",
          "required": false,
          "type": "TEXT"
        }
      ]
    },
    {
      "title": "Existing Agreement",
      "fields": [
        {
          "name": "has_existing_agreement",
          "label": "Existing agreement with us?",
          "required": true,
          "type": "CHOICE",
          "layout": "RADIO",
          "options": [
            {
              "label": "Yes",
              "value": "yes"
            },
            {
              "label": "No",
              "value": "no"
            }
          ]
        },
        {
          "name": "existing_agreement_id",
          "label": "Agreement ID",
          "required": true,
          "type": "TEXT",
          "condition": {
            "rules": [
              {
                "field": "has_existing_agreement",
                "operator": "EQUALS",
                "value": "yes"
              }
            ]
          }
        }
      ]
    }
  ]
}

{
  "name": "Employee Contract",
  "language": "EN",
  "caseFileTitleTemplate": "{{formName}} - {{primarySigner.name}} ({{primarySigner.email}})",
  "sections": [
    {
      "title": "Employee Details",
      "fields": [
        {
          "name": "full_name",
          "label": "Full Name",
          "required": true,
          "type": "TEXT",
          "validations": {
            "minLength": 2,
            "maxLength": 100
          }
        },
        {
          "name": "email_address",
          "label": "Email Address",
          "required": true,
          "type": "EMAIL"
        },
        {
          "name": "job_title",
          "label": "Job Title",
          "required": true,
          "type": "TEXT",
          "validations": {
            "maxLength": 100
          }
        },
        {
          "name": "start_date",
          "label": "Start Date",
          "required": true,
          "type": "DATE"
        }
      ]
    }
  ]
}

{
  "name": "Loan Application",
  "language": "EN",
  "description": "Demonstrates merge fields in HTML content. Answers collected in earlier sections are injected into a summary section so the applicant can review before signing.",
  "sections": [
    {
      "title": "Personal Information",
      "fields": [
        {
          "name": "full_name",
          "type": "TEXT",
          "label": "Full Name",
          "required": true,
          "mapTo": "primarySigner.name",
          "validations": {
            "minLength": 2,
            "maxLength": 100
          }
        },
        {
          "name": "email_address",
          "type": "EMAIL",
          "label": "Email Address",
          "required": true,
          "mapTo": "primarySigner.email"
        },
        {
          "name": "phone_number",
          "type": "PHONE",
          "label": "Phone Number",
          "required": true,
          "countryCodes": [
            "DK",
            "NO",
            "SE",
            "DE",
            "GB"
          ]
        }
      ]
    },
    {
      "title": "Loan Details",
      "fields": [
        {
          "name": "loan_amount",
          "type": "NUMBER",
          "label": "Loan Amount (DKK)",
          "required": true,
          "validations": {
            "min": 10000,
            "max": 500000
          }
        },
        {
          "name": "loan_purpose",
          "type": "CHOICE",
          "label": "Loan Purpose",
          "required": true,
          "layout": "SELECT",
          "options": [
            {
              "label": "Home Improvement",
              "value": "home_improvement"
            },
            {
              "label": "Vehicle Purchase",
              "value": "vehicle"
            },
            {
              "label": "Debt Consolidation",
              "value": "debt_consolidation"
            },
            {
              "label": "Education",
              "value": "education"
            },
            {
              "label": "Other",
              "value": "other"
            }
          ]
        },
        {
          "name": "repayment_period",
          "type": "CHOICE",
          "label": "Repayment Period",
          "required": true,
          "layout": "RADIO",
          "options": [
            {
              "label": "12 months",
              "value": "12"
            },
            {
              "label": "24 months",
              "value": "24"
            },
            {
              "label": "36 months",
              "value": "36"
            },
            {
              "label": "48 months",
              "value": "48"
            }
          ]
        }
      ]
    },
    {
      "title": "Application Summary",
      "fields": [
        {
          "type": "HTML",
          "content": "<p><strong>Please review your application:</strong></p><p>Applicant: <strong>{{full_name}}</strong></p><p>Email: {{email_address}}</p><p>Loan Amount: {{loan_amount}} DKK</p><p>Purpose: {{loan_purpose}}</p><p>Repayment: {{repayment_period}} months</p><p><em>By signing, you confirm all information is accurate.</em></p>"
        }
      ]
    }
  ]
}

{
  "name": "Contact Information",
  "language": "EN",
  "description": "Demonstrates the mapTo property. Fields mapped to primarySigner.name and primarySigner.email automatically identify the form filler as the primary signer — no separate signer configuration needed.",
  "sections": [
    {
      "title": "Your Details",
      "description": "We will use this information to identify you as the signer.",
      "fields": [
        {
          "name": "full_name",
          "type": "TEXT",
          "label": "Full Name",
          "required": true,
          "mapTo": "primarySigner.name",
          "validations": {
            "maxLength": 100
          }
        },
        {
          "name": "email_address",
          "type": "EMAIL",
          "label": "Email Address",
          "required": true,
          "mapTo": "primarySigner.email"
        },
        {
          "name": "phone_number",
          "type": "PHONE",
          "label": "Phone Number",
          "required": false,
          "countryCodes": [
            "DK",
            "NO",
            "SE",
            "DE",
            "GB"
          ]
        }
      ]
    }
  ]
}
